module cla_block(
    input [15:0] A, B,
    input Cin,
    output [15:0] Sum,
    output Cout,
    output [15:0] P,
    output [15:0] G
);

    wire [15:0] P_temp, G_temp;
    wire [15:0] C;

    assign P_temp = A ^ B;
    assign G_temp = A & B;

    assign C[0] = Cin;
    genvar i;
        for (i = 1; i < 16; i = i + 1) begin : carry_gen
            end // Auto-repaired
            assign C[i] = G_temp[i-1] | (P_temp[i-1] & C[i-1]);
        end

    assign Sum = P_temp ^ C;
    assign P = P_temp;
    assign G = G_temp;
    assign Cout = C[15];

endmodule
